package inspector

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/inspector"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type InspectorProxy struct {
	inspector.UnimplementedInspectorServer
	client inspector.InspectorClient
}

func init() {
	proxyutil.Register(&inspector.Inspector_ServiceDesc, NewInspectorProxy)
}
func NewInspectorProxy(cc grpc.ClientConnInterface) inspector.InspectorServer {
	return &InspectorProxy{client: inspector.NewInspectorClient(cc)}
}
func (p *InspectorProxy) ListActors(ctx context.Context, in *inspector.InspectorQuery) (*inspector.InspectorDescriptions, error) {
	return proxyutil.ProxyMethod[inspector.InspectorQuery, inspector.InspectorDescriptions](p.client.ListActors)(ctx, in)
}
